// ============================================================
// KILLCRITIC - DL Nexus V3
// Verificação de termos proibidos e validação de conteúdo
// ============================================================

const TERMOS_PROIBIDOS = [
  // Proibições legais / regulatórias
  'garantimos retorno',
  'lucro garantido',
  'sem risco',
  'investimento seguro',
  'proibido',
  'ilegal',
  // Proibições de conteúdo
  'whatsapp',
  'zap',
  'clique aqui e ganhe',
  'grátis por tempo limitado',
  // Sensacionalismo
  'urgente!!!',
  'imperdível!!!',
  'milagre',
  // Dados sensíveis
  'cpf',
  'senha',
  'token',
  'api_key',
  'secret'
];

const TERMOS_OBRIGATORIOS_CONTEXTO = [
  'avaliação técnica',
  'avaliacao tecnica',
  'diagnóstico',
  'diagnóstico gratuito',
  'visita técnica',
  'visita tecnica',
  'dl soluções',
  'dl solucoes',
  'condomínio',
  'condominio'
];

const items = $input.all();
const resultados = [];

for (const item of items) {
  const body = item.json.body || {};
  const message = (body.message || '').toLowerCase();
  const imageUrl = body.image_url || '';
  const approved = body.approved;

  // Validações básicas
  if (!message || message.trim().length === 0) {
    resultados.push({
      json: {
        ...item.json,
        killcritic_status: 'BLOQUEADO',
        killcritic_motivo: 'Mensagem vazia. Campo message é obrigatório.',
        killcritic_aprovado: false
      }
    });
    continue;
  }

  if (message.length < 10) {
    resultados.push({
      json: {
        ...item.json,
        killcritic_status: 'BLOQUEADO',
        killcritic_motivo: 'Mensagem muito curta (mínimo 10 caracteres).',
        killcritic_aprovado: false
      }
    });
    continue;
  }

  if (message.length > 63206) {
    resultados.push({
      json: {
        ...item.json,
        killcritic_status: 'BLOQUEADO',
        killcritic_motivo: 'Mensagem excede o limite do Facebook (63.206 caracteres).',
        killcritic_aprovado: false
      }
    });
    continue;
  }

  // Verificação de termos proibidos
  const termosEncontrados = TERMOS_PROIBIDOS.filter(termo =>
    message.includes(termo.toLowerCase())
  );

  if (termosEncontrados.length > 0) {
    resultados.push({
      json: {
        ...item.json,
        killcritic_status: 'BLOQUEADO',
        killcritic_motivo: `Termos proibidos detectados: ${termosEncontrados.join(', ')}`,
        killcritic_aprovado: false,
        killcritic_termos_detectados: termosEncontrados
      }
    });
    continue;
  }

  // Verificação de contexto obrigatório (pelo menos 1 termo de contexto)
  const temContexto = TERMOS_OBRIGATORIOS_CONTEXTO.some(termo =>
    message.includes(termo.toLowerCase())
  );

  if (!temContexto) {
    resultados.push({
      json: {
        ...item.json,
        killcritic_status: 'BLOQUEADO',
        killcritic_motivo: 'Post não menciona contexto DL / condomínio / avaliação técnica. Revisar alinhamento com identidade da marca.',
        killcritic_aprovado: false
      }
    });
    continue;
  }

  // Validação de URL de imagem (se fornecida)
  if (imageUrl) {
    const urlValida = /^https?:\/\/.+\.(jpg|jpeg|png|gif|webp)(\?.*)?$/i.test(imageUrl);
    if (!urlValida) {
      resultados.push({
        json: {
          ...item.json,
          killcritic_status: 'BLOQUEADO',
          killcritic_motivo: 'image_url fornecida não é uma URL de imagem válida (deve terminar em .jpg, .jpeg, .png, .gif ou .webp).',
          killcritic_aprovado: false
        }
      });
      continue;
    }
  }

  // APROVADO
  resultados.push({
    json: {
      ...item.json,
      killcritic_status: 'APROVADO',
      killcritic_motivo: 'Conteúdo validado com sucesso pelo KILLCRITIC.',
      killcritic_aprovado: true,
      killcritic_timestamp: new Date().toISOString()
    }
  });
}

return resultados;
